import {
    SHOW_LOADER,
    HIDE_LOADER,
    CHANGE_PAGINATION,
    SAVE_PAGINATION_TOTAL_COUNT,
    SAVE_FULL_MACHINES_DATA
} from '../constants/constants.js'


const initialState = {
    data: [],
    isLoading: false,
    pagination: {
        current: 1,
        pageSize: 6,
    }
}

export default function appReduces(state = initialState, action) {
    switch (action.type) {
        case SAVE_FULL_MACHINES_DATA:
            return { ...state, data: [...action.payload] }
        case SAVE_PAGINATION_TOTAL_COUNT:
            return { ...state, pagination: { ...state.pagination, total: action.payload } }
        case CHANGE_PAGINATION:
            return { ...state, pagination: { ...state.pagination, ...action.payload } }
        case SHOW_LOADER:
            return { ...state, isLoading: true }
        case HIDE_LOADER:
            return { ...state, isLoading: false }
        default:
            return state
    }
}