import React, { useEffect } from 'react'
import { useSelector, useDispatch } from 'react-redux'
import 'antd/dist/antd.css'
import { Table } from 'antd'
import './MachineTable.css'
import { loadMachines, changePagination } from '../../actions/machines'


const columns = [
    {
        title: 'VIN',
        dataIndex: 'vin',
    },
    {
        title: 'Brand',
        dataIndex: 'brand',
    },
    {
        title: 'Model',
        dataIndex: 'model',
    },
    {
        title: 'Grade',
        dataIndex: 'grade',
    },
    {
        title: 'Имя дилера',
        dataIndex: 'nameDiler',
    },
    {
        title: 'Адрес дилера',
        dataIndex: 'adresDiler',
    },
]


function MachineTable() {
    const dispatch = useDispatch()
    const dataMachines = useSelector(store => store.machines.data)
    const isLoading = useSelector(store => store.machines.isLoading)
    const pagination = useSelector(store => store.machines.pagination)
    let data

    useEffect(() => {
        dispatch(loadMachines(pagination))
    }, [])


    if (dataMachines.length > 0) {
        data = dataMachines.map(({ vin, brand, model, grade, id, dealerName, dealerOffice }) => {
            return (
                {
                    key: id,
                    vin,
                    brand,
                    model,
                    grade,
                    nameDiler: dealerName,
                    adresDiler: generateAddresses(dealerOffice)
                }
            )
        })
    }

    function generateAddresses(addresses) {
        const unicAddresses = new Set()

        if (addresses !== undefined && addresses.length > 0  ) {
            addresses.map((address) => {
                return unicAddresses.add(address.address)
            })

            return [...unicAddresses].map((address, i) => {
                return (
                    <span className="table-td__inn" key={i}>{address}</span>
                )
            })
        }
    }

    const handleTableChange = (pagination) => {
        dispatch(changePagination(pagination))
        dispatch(loadMachines(pagination))
    }


    return (
        <div className="machine-table">
            <h2>MachineTable</h2>
            <div className="machine-table__wrap">
                <Table
                    columns={columns}
                    dataSource={data}
                    size="small"
                    loading={isLoading}
                    pagination={pagination}
                    onChange={handleTableChange}
                />
            </div>
        </div>
    )
}


export default MachineTable
