import {
    LOAD_MACHINES,
    CHANGE_PAGINATION,
    SAVE_PAGINATION_TOTAL_COUNT,
    SAVE_FULL_MACHINES_DATA
} from '../constants/constants.js'


export function loadMachines(pagination) {
    return {
        type: LOAD_MACHINES,
        payload: pagination,
    }
}


export function saveTotalCountData(data) {
    return {
        type: SAVE_PAGINATION_TOTAL_COUNT,
        payload: data,
    }
}


export function saveFullMachinesData(data) {
    return {
        type: SAVE_FULL_MACHINES_DATA,
        payload: data,
    }
}


export function changePagination(pagination) {
    return {
        type: CHANGE_PAGINATION,
        payload: pagination,
    }
}