export default class PerxApiDb {
    _apiBase = 'https://jlrc.dev.perx.ru/carstock/api/v1/'


    getListMachine = async (page, perPage) => {
        const api_call = await fetch(`${this._apiBase}vehicles/?state=active&hidden=false&group=new&page=${page}&per_page=${perPage}`, {
            headers: {
                "X-CS-Dealer-Id-Only": "1",
                "Content-Type": "application/json",
            },
        })

        const totalCount = api_call.headers.get('X-Total-Count')
        const machines = await api_call.json()

        return {
            machines, 
            totalCount
        }
    }


    getDilerInfo = async (ids) => {
        const api_call = await fetch(`${this._apiBase}dealers/?id__in=${ids}`)
        const response = await api_call.json()
        return response
    }
}