import { takeEvery, put, call, select } from 'redux-saga/effects'
import { LOAD_MACHINES } from '../constants/constants.js'
import { saveFullMachinesData, saveTotalCountData } from '../actions/machines'
import { showLoader, hideLoader } from '../actions/toggleLoader'
import { saveDealerInfo } from '../actions/dealer'
import PerxApiDb from '../service/perx-api'
import * as selectors from '../selectors/selectors'


function* workerLoadMachines(action) {
    const perxApi = new PerxApiDb()
    const { current, pageSize } = action.payload

    yield put(showLoader())

    try {
        let { machines, totalCount } = yield perxApi.getListMachine(current, pageSize)
        yield put(saveTotalCountData(totalCount))

        let dealersId = yield call(getUnicDealerID, machines)
        const dealersInStoreInitial = yield select(selectors.dealers)
        let dealersWhoNotInStore = yield call(getDealerWhoNotInStore, dealersId, dealersInStoreInitial)

        let dealersInfo = yield call(getDilerData, dealersId, dealersWhoNotInStore)
        yield put(saveDealerInfo(dealersInfo))

        const dealersInStore = yield select(selectors.dealers)
        let machinesFullData = yield call(generateFullInfoAboutMachine, machines, dealersInStore)
        yield put(saveFullMachinesData(machinesFullData))
    }

    catch (error) {
        console.log('error', error)
    }

    yield put(hideLoader())
}


export function* watchLoadData() {
    yield takeEvery(LOAD_MACHINES, workerLoadMachines)
}


function getDilerData(dealersId, dealersWhoNotInStore) {
    const perxApi = new PerxApiDb()

    if (dealersWhoNotInStore.length > 0) {
        return perxApi.getDilerInfo(dealersWhoNotInStore.toString())
    } else if (dealersWhoNotInStore.length === 0) {
        return []
    }
    else if (!dealersWhoNotInStore) {
        return perxApi.getDilerInfo(dealersId.toString())
    }
}

function getDealerWhoNotInStore(dealersIDs, dealersInStore) {
    let array = []

    if (dealersInStore.length === 0) {
        return false
    }

    for (let id of dealersIDs) {
        if (!dealersInStore.some(dealer => dealer.id === id)) {
            array.push(id)
        }
    }

    return array
}

function getUnicDealerID(machines) {
    let unicDealerArray = []

    machines.map((item, i) => {
        if (!unicDealerArray.includes(item.dealer)) {
            unicDealerArray.push(item.dealer)
        }
        return item
    })

    return unicDealerArray
}

function generateFullInfoAboutMachine(machines, dealersInfo) {
    return machines.map(machine => {
        let index = dealersInfo.findIndex(ite => ite.id === machine.dealer)
        machine.dealerOffice = dealersInfo[index].offices
        return machine
    })
}
